#include <stdio.h>
int g_uninit;
int g_array[4];
int counter(void) {
    static int count = 0;
    return ++count;
}
int main(void) {
    printf("g_uninit: %d\n", g_uninit);
    printf("g_array: %d %d %d %d\n", g_array[0], g_array[1], g_array[2], g_array[3]);
    printf("All BSS zero: %s\n",
        (g_uninit == 0 && g_array[0] == 0 && g_array[3] == 0) ? "yes" : "no");
    printf("call1: %d\n", counter());
    printf("call2: %d\n", counter());
    printf("call3: %d\n", counter());
    printf("Static persists: yes\n");
    return 0;
}

